'use client';

import { createContext, useContext, useEffect, useState, ReactNode } from 'react';
import { useTheme } from 'next-themes';
import { Settings, DEFAULT_SETTINGS, ThemeSetting } from '@/types/settings';
import { getUserLocale } from '@/lib/formatting';

const STORAGE_KEY = 'stellar_route_settings';

interface SettingsContextType {
  settings: Settings;
  updateSlippage: (value: number) => void;
  updateTheme: (theme: ThemeSetting) => void;
  updateLocale: (locale: Settings['locale']) => void;
  resetSettings: () => void;
}

const SettingsContext = createContext<SettingsContextType | undefined>(undefined);

export function SettingsProvider({ children }: { children: ReactNode }) {
  const { theme, setTheme } = useTheme();
  const [settings, setSettings] = useState<Settings>(() => {
    if (typeof window === 'undefined') return DEFAULT_SETTINGS;
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      const parsed = stored ? (JSON.parse(stored) as Partial<Settings>) : {};
      return {
        ...DEFAULT_SETTINGS,
        ...parsed,
        theme: (theme as ThemeSetting) || parsed.theme || DEFAULT_SETTINGS.theme,
        locale: parsed.locale || getUserLocale(),
      };
    } catch (e) {
      console.error('Failed to load settings', e);
      return DEFAULT_SETTINGS;
    }
  });

  // Sync with next-themes theme
  useEffect(() => {
    if (theme) {
      setSettings((prev) => ({ ...prev, theme: theme as ThemeSetting }));
    }
  }, [theme]);

  // Handle local storage saving
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(settings));
    } catch (e) {
      console.error('Failed to save settings', e);
    }
  }, [settings]);

  const isValidSlippage = (value: number) => Number.isFinite(value) && value >= 0 && value <= 50;

  const updateSlippage = (value: number) => {
    if (!isValidSlippage(value)) {
      console.warn(`Ignored invalid slippage value: ${value}`);
      return;
    }

    setSettings((prev) => ({ ...prev, slippageTolerance: value }));
  };

  const updateTheme = (newTheme: ThemeSetting) => {
    setTheme(newTheme);
    setSettings((prev) => ({ ...prev, theme: newTheme }));
  };

  const updateLocale = (locale: Settings['locale']) => {
    setSettings((prev) => ({ ...prev, locale }));
  };

  const resetSettings = () => {
    setTheme(DEFAULT_SETTINGS.theme);
    setSettings(DEFAULT_SETTINGS);
  };

  return (
    <SettingsContext.Provider
      value={{
        settings,
        updateSlippage,
        updateTheme,
        updateLocale,
        resetSettings,
      }}
    >
      {children}
    </SettingsContext.Provider>
  );
}

export function useSettings() {
  const context = useContext(SettingsContext);
  if (context === undefined) {
    throw new Error('useSettings must be used within a SettingsProvider');
  }
  return context;
}

import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { render, screen, fireEvent, waitFor, cleanup } from "@testing-library/react";
import { TokenSearchModal } from "@/components/shared/TokenSearchModal";

vi.mock("sonner", () => ({
  toast: { success: vi.fn(), error: vi.fn() },
}));

const assets = [
  { code: "XLM", asset: "native", displayName: "XLM" },
  {
    code: "USDC",
    asset: "USDC:GA5ZSEJYB37JRC5AVCIA5MOP4RHTM335X2KGX3IHOJAPP5RE34K4KZVN",
    issuer: "GA5ZSEJYB37JRC5AVCIA5MOP4RHTM335X2KGX3IHOJAPP5RE34K4KZVN",
    displayName: "USDC",
  },
  {
    code: "AQUA",
    asset: "AQUA:GBNZILSTVQZ4R7IKQDGHYGY2QXL5QOFJYQMXPKWRRM5PAV7Y4M67AQUA",
    issuer: "GBNZILSTVQZ4R7IKQDGHYGY2QXL5QOFJYQMXPKWRRM5PAV7Y4M67AQUA",
    displayName: "AQUA",
  },
];

describe("TokenSearchModal", () => {
  beforeEach(() => {
    localStorage.clear();
  });

  afterEach(() => {
    cleanup();
    localStorage.clear();
  });

  it("renders when open", () => {
    render(
      <TokenSearchModal
        isOpen={true}
        onClose={vi.fn()}
        assets={assets}
        onSelect={vi.fn()}
        title="Select token"
      />
    );
    expect(screen.getByText("Select token")).toBeDefined();
    expect(screen.getByPlaceholderText(/search by symbol or address/i)).toBeDefined();
  });

  it("does not render when closed", () => {
    render(
      <TokenSearchModal
        isOpen={false}
        onClose={vi.fn()}
        assets={assets}
        onSelect={vi.fn()}
        title="Select token"
      />
    );
    expect(screen.queryByText("Select token")).toBeNull();
  });

  it("shows all assets initially", () => {
    render(
      <TokenSearchModal
        isOpen={true}
        onClose={vi.fn()}
        assets={assets}
        onSelect={vi.fn()}
        title="Select token"
      />
    );
    expect(screen.getByText("XLM")).toBeDefined();
    expect(screen.getByText("USDC")).toBeDefined();
    expect(screen.getByText("AQUA")).toBeDefined();
  });

  it("filters by symbol", async () => {
    render(
      <TokenSearchModal
        isOpen={true}
        onClose={vi.fn()}
        assets={assets}
        onSelect={vi.fn()}
        title="Select token"
      />
    );

    const input = screen.getByPlaceholderText(/search by symbol or address/i);
    fireEvent.change(input, { target: { value: "USDC" } });

    await waitFor(() => {
      expect(screen.getByText("USDC")).toBeDefined();
      expect(screen.queryByText("AQUA")).toBeNull();
    });
  });

  it("filters by issuer address", async () => {
    render(
      <TokenSearchModal
        isOpen={true}
        onClose={vi.fn()}
        assets={assets}
        onSelect={vi.fn()}
        title="Select token"
      />
    );

    const input = screen.getByPlaceholderText(/search by symbol or address/i);
    fireEvent.change(input, { target: { value: "GA5ZSE" } });

    await waitFor(() => {
      expect(screen.getByText("USDC")).toBeDefined();
      expect(screen.queryByText("AQUA")).toBeNull();
    });
  });

  it("shows empty state when no results found", async () => {
    render(
      <TokenSearchModal
        isOpen={true}
        onClose={vi.fn()}
        assets={assets}
        onSelect={vi.fn()}
        title="Select token"
      />
    );

    const input = screen.getByPlaceholderText(/search by symbol or address/i);
    fireEvent.change(input, { target: { value: "NONEXISTENT" } });

    await waitFor(() => {
      expect(screen.getByText("No tokens found")).toBeDefined();
      expect(screen.getByText(/try searching by contract address/i)).toBeDefined();
    });
  });

  it("calls onSelect and onClose when token is clicked", async () => {
    const onSelect = vi.fn();
    const onClose = vi.fn();

    render(
      <TokenSearchModal
        isOpen={true}
        onClose={onClose}
        assets={assets}
        onSelect={onSelect}
        title="Select token"
      />
    );

    const xlmButtons = screen.getAllByText("XLM");
    const tokenButton = xlmButtons[0].closest("button")!;
    fireEvent.click(tokenButton);

    expect(onSelect).toHaveBeenCalledWith("native");
    expect(onClose).toHaveBeenCalled();
  });

  it("shows check icon on selected asset", () => {
    render(
      <TokenSearchModal
        isOpen={true}
        onClose={vi.fn()}
        assets={assets}
        onSelect={vi.fn()}
        title="Select token"
        selectedAsset="native"
      />
    );

    // Check icon rendered via mock will be an svg, we verify the button has selected styling
    // by querying the data-token-item buttons
    const tokenButtons = screen.getAllByRole("button", { hidden: true });
    const xlmButton = tokenButtons.find((b) =>
      b.getAttribute("data-token-item") !== null &&
      b.textContent?.includes("XLM")
    );
    expect(xlmButton).toBeDefined();
  });

  it("keyboard: ArrowDown moves selection, Enter selects", async () => {
    const onSelect = vi.fn();
    const onClose = vi.fn();

    render(
      <TokenSearchModal
        isOpen={true}
        onClose={onClose}
        assets={assets}
        onSelect={onSelect}
        title="Select token"
      />
    );

    const input = screen.getByPlaceholderText(/search by symbol or address/i);

    // Move down once (from index 0 to 1) and press Enter
    fireEvent.keyDown(input, { key: "ArrowDown" });
    fireEvent.keyDown(input, { key: "Enter" });

    expect(onSelect).toHaveBeenCalled();
    expect(onClose).toHaveBeenCalled();
  });

  it("keyboard: ArrowUp wraps to last item", async () => {
    const onSelect = vi.fn();
    const onClose = vi.fn();

    render(
      <TokenSearchModal
        isOpen={true}
        onClose={onClose}
        assets={assets}
        onSelect={onSelect}
        title="Select token"
      />
    );

    const input = screen.getByPlaceholderText(/search by symbol or address/i);

    // ArrowUp from index 0 should wrap to last (index 2: AQUA)
    fireEvent.keyDown(input, { key: "ArrowUp" });
    fireEvent.keyDown(input, { key: "Enter" });

    // Should select the last item (AQUA)
    expect(onSelect).toHaveBeenCalledWith(
      "AQUA:GBNZILSTVQZ4R7IKQDGHYGY2QXL5QOFJYQMXPKWRRM5PAV7Y4M67AQUA"
    );
  });

  it("clears search when X button is clicked", async () => {
    render(
      <TokenSearchModal
        isOpen={true}
        onClose={vi.fn()}
        assets={assets}
        onSelect={vi.fn()}
        title="Select token"
      />
    );

    const input = screen.getByPlaceholderText(/search by symbol or address/i);
    fireEvent.change(input, { target: { value: "USDC" } });

    await waitFor(() => {
      expect(screen.queryByText("AQUA")).toBeNull();
    });

    const clearButton = screen.getByRole("button", {
      name: (_, el) => el?.querySelector("svg") !== null && el.textContent === "",
      hidden: true,
    });
    // Find the clear X button by looking after the input
    const allButtons = screen.getAllByRole("button", { hidden: true });
    const xButton = allButtons.find(
      (b) => !b.hasAttribute("data-token-item") && b.textContent === ""
    );
    if (xButton) fireEvent.click(xButton);

    await waitFor(() => {
      expect(screen.getByText("AQUA")).toBeDefined();
    });
  });

  it("shows recent tokens section when there are recent picks", async () => {
    // Pre-populate localStorage with a recent token
    localStorage.setItem("stellar-route-recent-tokens", JSON.stringify(["native"]));

    render(
      <TokenSearchModal
        isOpen={true}
        onClose={vi.fn()}
        assets={assets}
        onSelect={vi.fn()}
        title="Select token"
      />
    );

    // The recent section shows after the hook hydrates
    await waitFor(() => {
      expect(screen.getByText("RECENT")).toBeDefined();
    });
  });
});

"use client";

import React, { useMemo, useState, useEffect, useRef } from "react";
import { Search, X, History, Check } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";
import { useRecentTokens } from "@/hooks/useRecentTokens";

export interface AssetOption {
  code: string;
  asset: string;
  issuer?: string;
  displayName?: string;
}

interface TokenSearchModalProps {
  isOpen: boolean;
  onClose: () => void;
  assets: AssetOption[];
  onSelect: (asset: string) => void;
  title: string;
  selectedAsset?: string;
}

export function TokenSearchModal({
  isOpen,
  onClose,
  assets,
  onSelect,
  title,
  selectedAsset,
}: TokenSearchModalProps) {
  const [search, setSearch] = useState("");
  const [selectedIndex, setSelectedIndex] = useState(0);
  const { recentTokens, addRecentToken } = useRecentTokens();
  const inputRef = useRef<HTMLInputElement>(null);
  const listRef = useRef<HTMLDivElement>(null);

  // Filter assets based on search
  const filteredAssets = useMemo(() => {
    const query = search.toLowerCase().trim();
    if (!query) return assets;

    return assets.filter(
      (a) =>
        a.code.toLowerCase().includes(query) ||
        a.asset.toLowerCase().includes(query) ||
        a.issuer?.toLowerCase().includes(query) ||
        a.displayName?.toLowerCase().includes(query)
    );
  }, [assets, search]);

  // Recent assets based on the persisted IDs
  const recentAssets = useMemo(() => {
    return recentTokens
      .map((id) => assets.find((a) => a.asset === id))
      .filter((a): a is AssetOption => !!a);
  }, [recentTokens, assets]);

  // Reset selected index when search changes
  useEffect(() => {
    setSelectedIndex(0);
  }, [search]);

  // Handle keyboard navigation
  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (filteredAssets.length === 0) return;

    if (e.key === "ArrowDown") {
      e.preventDefault();
      setSelectedIndex((prev) => (prev + 1) % filteredAssets.length);
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      setSelectedIndex(
        (prev) => (prev - 1 + filteredAssets.length) % filteredAssets.length
      );
    } else if (e.key === "Enter") {
      e.preventDefault();
      if (filteredAssets[selectedIndex]) {
        handleSelect(filteredAssets[selectedIndex].asset);
      }
    }
  };

  const handleSelect = (asset: string) => {
    addRecentToken(asset);
    onSelect(asset);
    onClose();
  };

  // Scroll active item into view
  useEffect(() => {
    if (listRef.current && selectedIndex >= 0) {
      const listElement = listRef.current.querySelector('[data-radix-scroll-area-viewport]');
      if (!listElement) return;
      
      const items = listElement.querySelectorAll('button[data-token-item]');
      const activeItem = items[selectedIndex] as HTMLElement;
      
      if (activeItem) {
        activeItem.scrollIntoView?.({ block: "nearest" });
      }
    }
  }, [selectedIndex]);

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-md p-0 overflow-hidden flex flex-col h-[600px] max-h-[85vh]">
        <DialogHeader className="p-4 pb-2 border-b">
          <DialogTitle>{title}</DialogTitle>
        </DialogHeader>

        <div className="p-4 space-y-4 flex flex-col flex-1 overflow-hidden">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              ref={inputRef}
              placeholder="Search by symbol or address..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              onKeyDown={handleKeyDown}
              className="pl-9 h-11"
              autoFocus
            />
            {search && (
              <button
                onClick={() => setSearch("")}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
              >
                <X className="h-4 w-4" />
              </button>
            )}
          </div>

          {!search && recentAssets.length > 0 && (
            <div className="space-y-2">
              <div className="flex items-center gap-2 text-xs font-semibold text-muted-foreground">
                <History className="h-3 w-3" />
                RECENT
              </div>
              <div className="flex flex-wrap gap-2">
                {recentAssets.map((asset) => (
                  <Button
                    key={`recent-${asset.asset}`}
                    variant="outline"
                    size="sm"
                    className="h-8 py-1 px-3 gap-2"
                    onClick={() => handleSelect(asset.asset)}
                  >
                    <span className="font-medium">{asset.code}</span>
                  </Button>
                ))}
              </div>
            </div>
          )}

          <div className="flex-1 overflow-hidden flex flex-col min-h-0">
            <div className="text-xs font-semibold text-muted-foreground mb-2 flex items-center justify-between">
              <span>TOKENS</span>
              <span>{filteredAssets.length} results</span>
            </div>
            <ScrollArea className="flex-1 -mx-4 px-4" ref={listRef}>
              <div className="space-y-1 pb-4">
                {filteredAssets.length === 0 ? (
                  <div className="py-20 text-center">
                    <p className="text-muted-foreground">No tokens found</p>
                    <p className="text-xs text-muted-foreground/60 mt-1">
                      Try searching by contract address or another symbol
                    </p>
                  </div>
                ) : (
                  filteredAssets.map((asset, index) => (
                    <button
                      key={asset.asset}
                      data-token-item
                      className={cn(
                        "w-full flex items-center justify-between p-3 rounded-lg transition-all text-left outline-none",
                        selectedIndex === index
                          ? "bg-accent text-accent-foreground"
                          : "hover:bg-accent/50",
                        selectedAsset === asset.asset &&
                          "ring-1 ring-primary/50 bg-primary/5"
                      )}
                      onClick={() => handleSelect(asset.asset)}
                      onMouseEnter={() => setSelectedIndex(index)}
                    >
                      <div className="flex flex-col min-w-0">
                        <div className="flex items-center gap-2">
                          <span className="font-bold underline decoration-primary/20 decoration-2 underline-offset-2">
                            {asset.code}
                          </span>
                          {asset.displayName &&
                            asset.displayName !== asset.code && (
                              <span className="text-xs text-muted-foreground truncate max-w-[150px]">
                                {asset.displayName}
                              </span>
                            )}
                        </div>
                        {asset.issuer && (
                          <span className="text-[10px] font-mono text-muted-foreground truncate w-full max-w-[200px]">
                            {asset.issuer}
                          </span>
                        )}
                      </div>
                      <div className="flex items-center gap-2">
                        {selectedAsset === asset.asset && (
                          <Check className="h-4 w-4 text-primary" />
                        )}
                      </div>
                    </button>
                  ))
                )}
              </div>
            </ScrollArea>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { RouteVisualization } from './RouteVisualization';
import { SplitRouteVisualization } from './SplitRouteVisualization';
import { PathStep, PriceQuote } from '@/types';
import { SplitRouteData, RouteMetrics } from '@/types/route';

interface TradeRouteDisplayProps {
  quote: PriceQuote | null;
  isLoading?: boolean;
  error?: string;
  className?: string;
}

function isSplitRoute(_path: PathStep[]): boolean {
  // For now, we assume all routes are single-path
  // In the future, the API might return split route information
  return false;
}

function convertToSplitRoute(path: PathStep[]): SplitRouteData {
  // Placeholder conversion - actual implementation would parse API response
  return {
    paths: [
      {
        percentage: 100,
        steps: path,
      },
    ],
    totalOutput: '0',
  };
}

function calculateMetrics(quote: PriceQuote): RouteMetrics {
  // Calculate metrics from quote data
  const hops = Math.max(quote.path.length, 1);
  const totalFees = `${(hops * 0.00001).toFixed(5)} XLM`;
  const totalPriceImpact = quote.priceImpact != null
    ? `${quote.priceImpact}${quote.priceImpact.includes('%') ? '' : '%'}`
    : 'N/A';
  const netOutput = quote.total;
  const averageRate = quote.price;

  return {
    totalFees,
    totalPriceImpact,
    netOutput,
    averageRate,
  };
}

export function TradeRouteDisplay({
  quote,
  isLoading = false,
  error,
  className,
}: TradeRouteDisplayProps) {
  const [displayError, setDisplayError] = useState<string | undefined>(error);
  const breakdown = quote
    ? {
        hops: quote.path.length,
        totalFees: `${(Math.max(quote.path.length, 1) * 0.00001).toFixed(5)} XLM`,
        priceImpact:
          quote.priceImpact != null
            ? `${quote.priceImpact}${quote.priceImpact.includes('%') ? '' : '%'}`
            : 'N/A',
      }
    : undefined;

  useEffect(() => {
    setDisplayError(error);
  }, [error]);

  // Loading state
  if (isLoading) {
    return (
      <RouteVisualization path={[]} isLoading={true} className={className} />
    );
  }

  // Error state
  if (displayError) {
    return (
      <RouteVisualization
        path={[]}
        error={displayError}
        className={className}
      />
    );
  }

  // No quote
  if (!quote) {
    return <RouteVisualization path={[]} className={className} />;
  }

  // Check if split route
  if (isSplitRoute(quote.path)) {
    const splitRoute = convertToSplitRoute(quote.path);
    const metrics = calculateMetrics(quote);
    return (
      <SplitRouteVisualization
        splitRoute={splitRoute}
        metrics={metrics}
        className={className}
      />
    );
  }

  // Regular single-path route
  return (
    <RouteVisualization
      path={quote.path}
      className={className}
      breakdown={breakdown}
    />
  );
}

/**
 * Placeholder example — for live quotes use `useQuoteRefresh` from
 * `@/hooks/useQuoteRefresh` with `stellarRouteClient.getQuote` (see `DemoSwap`).
 * A future WebSocket quote stream can push updates into the same hook.
 */
export function TradeRouteExample() {
  return (
    <div className="space-y-4">
      <TradeRouteDisplay quote={null} />
    </div>
  );
}

