import { useMemo, useState, useEffect } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { PathStep } from "@/types";
import { RouteVisualization } from "./RouteVisualization";
import { CopyButton } from "./CopyButton";
import { describeTradeRoute } from "@/lib/route-helpers";
import { TransactionStatus } from "@/types/transaction";
import {
  ArrowDown,
  CheckCircle2,
  XCircle,
  Loader2,
  Wallet,
  ExternalLink,
  ChevronRight,
  TriangleAlert,
  AlertCircle,
  Info,
} from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import { getSlippageWarningLevel } from "@/lib/slippage";

export interface BatchSwapItem {
  fromAsset: string;
  fromAmount: string;
  toAsset: string;
  toAmount: string;
  exchangeRate: string;
  priceImpact: string;
  routePath: PathStep[];
}

interface TransactionConfirmationModalProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  // Batch details (if provided, individual trade details below are ignored for the main view)
  swaps?: BatchSwapItem[];
  // Individual trade details (legacy / single mode)
  fromAsset?: string;
  fromAmount?: string;
  toAsset?: string;
  toAmount?: string;
  exchangeRate?: string;
  priceImpact?: string;
  minReceived?: string;
  networkFee: string;
  slippageTolerancePct?: number;
  routePath?: PathStep[];
  // Actions
  onConfirm: () => void;
  onCancel?: () => void;
  confirmDisabled?: boolean;
  confirmDisabledReason?: string;
  // State
  status: TransactionStatus | "review";
  errorMessage?: string;
  txHash?: string;
}

function parseMaybeNumber(value: string | undefined): number | undefined {
  if (!value) return undefined;
  const n = Number(value);
  if (!Number.isFinite(n)) return undefined;
  return n;
}

export function TransactionConfirmationModal({
  isOpen,
  onOpenChange,
  fromAsset,
  fromAmount,
  toAsset,
  toAmount,
  exchangeRate,
  priceImpact,
  minReceived,
  networkFee,
  slippageTolerancePct,
  routePath,
  onConfirm,
  onCancel,
  confirmDisabled = false,
  confirmDisabledReason,
  status,
  errorMessage,
  txHash,
  swaps,
}: TransactionConfirmationModalProps) {
  const [countdown, setCountdown] = useState(15);

  const priceImpactValue = useMemo(() => {
    if (swaps && swaps.length > 0) {
      return Math.max(...swaps.map((s) => parseFloat(s.priceImpact) || 0));
    }
    return parseFloat(priceImpact || "0") || 0;
  }, [priceImpact, swaps]);

  const isHighPriceImpact = priceImpactValue >= 2;
  const isSeverePriceImpact = priceImpactValue >= 5;

  const slippageWarningLevel = getSlippageWarningLevel(
    slippageTolerancePct ?? null,
  );
  const isHighSlippage = slippageWarningLevel === "high";
  const isLowSlippage = slippageWarningLevel === "low";

  const computedMinReceived = useMemo(() => {
    const toAmountN = parseMaybeNumber(toAmount);
    if (toAmountN === undefined) return undefined;
    if (slippageTolerancePct === undefined) return undefined;

    const slippageFactor = 1 - slippageTolerancePct / 100;
    if (!(slippageFactor >= 0)) return undefined;

    return String(toAmountN * slippageFactor);
  }, [slippageTolerancePct, toAmount]);

  const minReceivedToDisplay = computedMinReceived ?? minReceived;

  // Auto-refresh mock timer during review state
  useEffect(() => {
    let timer: ReturnType<typeof setInterval> | undefined;
    if (isOpen && status === "review") {
      setCountdown(15);
      timer = setInterval(() => {
        setCountdown((prev: number) => {
          if (prev <= 1) return 15;
          return prev - 1;
        });
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [isOpen, status]);

  const handleOpenChange = (open: boolean) => {
    if (status === "review" || status === "success" || status === "failed") {
      onOpenChange(open);
      if (!open && onCancel) onCancel();
    }
  };

  const isBatch = swaps && swaps.length > 0;

  return (
    <Dialog open={isOpen} onOpenChange={handleOpenChange}>
      <DialogContent className="sm:max-w-[425px] w-[90vw] sm:w-auto">
        {/* REVIEW STATE */}
        {status === "review" && (
          <>
            <DialogHeader>
              <DialogTitle>Confirm Swap</DialogTitle>
              <DialogDescription>
                Review your transaction details before signing.
              </DialogDescription>
            </DialogHeader>

            <div className="space-y-4 py-4 max-h-[60vh] overflow-y-auto pr-1">
              {/* Batch or Single Swap Summary */}
              {isBatch ? (
                <div className="space-y-4">
                  <div className="flex items-center justify-between px-1">
                    <span className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">
                      Batch Swaps ({swaps!.length})
                    </span>
                    <Badge variant="outline" className="text-[10px]">
                      Atomics enabled
                    </Badge>
                  </div>
                  {swaps!.map((swap, i) => (
                    <div
                      key={i}
                      className="p-3 rounded-lg bg-muted/30 border space-y-2 relative overflow-hidden"
                    >
                      <div className="absolute top-0 right-0 p-1 opacity-10">
                        <span className="text-4xl font-black italic">
                          #{i + 1}
                        </span>
                      </div>
                      <div className="flex justify-between items-end relative z-10">
                        <div>
                          <p className="text-[10px] text-muted-foreground uppercase font-bold">
                            Pay
                          </p>
                          <p className="font-bold">
                            {swap.fromAmount} {swap.fromAsset}
                          </p>
                        </div>
                        <div className="text-center pb-1">
                          <ChevronRight className="w-4 h-4 text-muted-foreground/50" />
                        </div>
                        <div className="text-right">
                          <p className="text-[10px] text-muted-foreground uppercase font-bold">
                            Receive
                          </p>
                          <p className="font-bold text-success">
                            {swap.toAmount} {swap.toAsset}
                          </p>
                        </div>
                      </div>
                      <div className="pt-2 border-t border-border/40 flex justify-between items-center text-[10px] text-muted-foreground">
                        <span>Rate: {swap.exchangeRate}</span>
                        <span
                          className={cn(
                            parseFloat(swap.priceImpact) > 1
                              ? "text-destructive"
                              : "text-success"
                          )}
                        >
                          Impact: {swap.priceImpact}
                        </span>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                /* Single Swap Summary */
                <div className="p-4 rounded-lg bg-muted/30 border space-y-3">
                  <div className="flex justify-between items-center">
                    <span className="text-sm font-medium text-muted-foreground">
                      You Pay
                    </span>
                    <div className="text-right">
                      <p className="text-lg font-bold">
                        {fromAmount} {fromAsset}
                      </p>
                    </div>
                  </div>

                  <div className="flex justify-center -my-2 relative z-10">
                    <div className="bg-background border rounded-full p-1">
                      <ArrowDown className="w-4 h-4 text-muted-foreground" />
                    </div>
                  </div>

                  <div className="flex justify-between items-center">
                    <span className="text-sm font-medium text-muted-foreground">
                      You Receive
                    </span>
                    <div className="text-right">
                      <p className="text-lg font-bold text-success">
                        ~{toAmount} {toAsset}
                      </p>
                      <p className="text-[10px] text-muted-foreground uppercase tracking-wider">
                        Estimated Minimum: {minReceivedToDisplay ?? "—"}{" "}
                        {toAsset}
                      </p>
                    </div>
                  </div>
                </div>
              )}

              {/* Warnings Section */}
              {(isHighPriceImpact || isHighSlippage || isLowSlippage) && (
                <div className="space-y-2">
                  {isSeverePriceImpact ? (
                    <div className="flex gap-2 p-3 rounded-lg bg-destructive/10 border border-destructive/20 text-destructive text-xs">
                      <TriangleAlert className="w-4 h-4 shrink-0" />
                      <div>
                        <p className="font-bold">
                          Very High Price Impact ({priceImpact})
                        </p>
                        <p>
                          This trade will significantly move the market price.
                          You may receive much less than expected.
                        </p>
                      </div>
                    </div>
                  ) : isHighPriceImpact ? (
                    <div className="flex gap-2 p-3 rounded-lg bg-amber-500/10 border border-amber-500/20 text-amber-600 dark:text-amber-400 text-xs">
                      <AlertCircle className="w-4 h-4 shrink-0" />
                      <div>
                        <p className="font-bold">
                          High Price Impact ({priceImpact})
                        </p>
                        <p>
                          The price for this trade is significantly different
                          from the current market rate.
                        </p>
                      </div>
                    </div>
                  ) : null}

                  {isHighSlippage && (
                    <div className="flex gap-2 p-2 rounded-lg bg-amber-500/10 border border-amber-500/20 text-amber-600 dark:text-amber-400 text-xs">
                      <Info className="w-4 h-4 shrink-0" />
                      <div>
                        <p className="font-medium text-amber-700 dark:text-amber-300">
                          High Slippage Tolerance ({slippageTolerancePct}%)
                        </p>
                        <p className="opacity-80">
                          Your transaction might be frontrun or you may receive
                          a much worse price.
                        </p>
                      </div>
                    </div>
                  )}

                  {isLowSlippage && (
                    <div className="flex gap-2 p-2 rounded-lg bg-amber-500/10 border border-amber-500/20 text-amber-600 dark:text-amber-400 text-xs">
                      <Info className="w-4 h-4 shrink-0" />
                      <div>
                        <p className="font-medium">Very Low Slippage</p>
                        <p className="opacity-80">
                          Transaction might fail if the price moves even
                          slightly before confirmation.
                        </p>
                      </div>
                    </div>
                  )}
                </div>
              )}

              {/* Trade Details */}
              <div className="space-y-2 text-sm">
                {!isBatch && (
                  <>
                    <div className="flex justify-between">
                      <span className="text-muted-foreground">Rate</span>
                      <span>
                        1 {fromAsset} = {exchangeRate} {toAsset}
                      </span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-muted-foreground">
                        Price Impact
                      </span>
                      <span
                        className={
                          parseFloat(priceImpact || "0") > 1
                            ? "text-destructive font-medium"
                            : "text-success font-medium"
                        }
                      >
                        {priceImpact}
                      </span>
                    </div>
                  </>
                )}
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Slippage</span>
                  <span>
                    {slippageTolerancePct === undefined
                      ? "—"
                      : `${slippageTolerancePct}%`}
                  </span>
                </div>
                {!isBatch && (
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">
                      Minimum Received
                    </span>
                    <span>
                      {minReceivedToDisplay ?? "—"} {toAsset}
                    </span>
                  </div>
                )}
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Network Fee</span>
                  <span>{networkFee} XLM</span>
                </div>
              <div className="flex flex-col gap-1 pt-2">
                <div className="flex items-center justify-between">
                  <span className="text-muted-foreground">Route</span>
                  <CopyButton
                    value={describeTradeRoute(routePath || [])}
                    label="Copy route summary"
                  />
                </div>
                <RouteVisualization
                  path={routePath || []}
                  className="border-none shadow-none bg-transparent p-0"
                />
              </div>
              </div>

              <div className="rounded-md border border-amber-500/40 bg-amber-500/10 px-3 py-2 text-xs text-amber-950 dark:text-amber-100">
                Demo mode: signing and submission are simulated — not yet
                on-chain.
              </div>
            </div>

            <DialogFooter className="flex-col sm:flex-col gap-2">
              <Button
                onClick={onConfirm}
                disabled={confirmDisabled}
                className="w-full min-h-[48px]"
                size="lg"
              >
                {isBatch ? "Confirm Batch Swaps" : "Confirm Swap"}
              </Button>
              {confirmDisabledReason && (
                <p className="w-full text-center text-xs text-destructive">
                  {confirmDisabledReason}
                </p>
              )}
              <Button
                type="button"
                variant="outline"
                className="w-full min-h-[48px]"
                onClick={() => handleOpenChange(false)}
              >
                Cancel
              </Button>
              <div className="text-center text-xs text-muted-foreground">
                Quote refreshes in {countdown}s
              </div>
            </DialogFooter>
          </>
        )}

        {/* AWAITING SIGNATURE STATE */}
        {status === "pending" && (
          <div className="py-12 flex flex-col items-center justify-center space-y-4 text-center">
            <div className="relative">
              <div className="absolute inset-0 bg-primary/20 rounded-full animate-ping" />
              <div className="bg-primary/10 p-4 rounded-full relative">
                <Wallet className="w-12 h-12 text-primary" />
              </div>
            </div>
            <div>
              <DialogTitle className="text-xl mb-2">
                Awaiting Signature
              </DialogTitle>
              <DialogDescription>
                Please confirm the transaction in your wallet to continue.
              </DialogDescription>
              <p className="mt-3 text-xs text-muted-foreground">
                Demo mode: this action is simulated — not yet on-chain.
              </p>
            </div>
          </div>
        )}

        {/* SUBMITTING / PROCESSING STATE */}
        {(status === "submitting" || status === "processing") && (
          <div className="py-12 flex flex-col items-center justify-center space-y-4 text-center">
            <Loader2 className="w-16 h-16 text-primary animate-spin" />
            <div>
              <DialogTitle className="text-xl mb-2">
                {status === "submitting" ? "Submitting..." : "Processing..."}
              </DialogTitle>
              <DialogDescription>
                Waiting for network confirmation. This should only take a few
                seconds.
              </DialogDescription>
            </div>
          </div>
        )}

        {/* SUCCESS STATE */}
        {status === "success" && (
          <div className="py-8 flex flex-col items-center justify-center space-y-6 text-center">
            <div className="bg-success/10 p-4 rounded-full">
              <CheckCircle2 className="w-16 h-16 text-success" />
            </div>
            <div>
              <DialogTitle className="text-2xl mb-2">
                {isBatch ? "Batch Successful!" : "Swap Successful!"}
              </DialogTitle>
              <DialogDescription>
                {swaps && swaps.length > 1 ? (
                  <span>
                    Processed {swaps.length} transactions in one atomic batch.
                  </span>
                ) : (
                  <>
                    You received{" "}
                    <span className="font-bold text-foreground">
                      {toAmount} {toAsset}
                    </span>
                  </>
                )}
              </DialogDescription>
            </div>

            {txHash && (
              <div className="min-h-[44px] flex flex-col items-center gap-2">
                <div className="flex items-center gap-1">
                  <span className="font-mono text-xs text-muted-foreground truncate max-w-[240px]">
                    {txHash}
                  </span>
                  <CopyButton value={txHash} label="Copy transaction hash" />
                </div>
                <a
                  href={`https://stellar.expert/explorer/public/tx/${txHash}`}
                  target="_blank"
                  rel="noreferrer"
                  className="flex items-center gap-1 text-sm text-primary hover:underline"
                >
                  View on Stellar Expert{" "}
                  <ExternalLink className="w-4 h-4" />
                </a>
              </div>
            )}

            <Button
              onClick={() => handleOpenChange(false)}
              className="w-full mt-4"
            >
              Done
            </Button>
          </div>
        )}

        {/* FAILED STATE */}
        {status === "failed" && (
          <div className="py-8 flex flex-col items-center justify-center space-y-6 text-center">
            <div className="bg-destructive/10 p-4 rounded-full">
              <XCircle className="w-16 h-16 text-destructive" />
            </div>
            <div>
              <DialogTitle className="text-xl mb-2">
                Transaction Failed
              </DialogTitle>
              <DialogDescription className="text-destructive max-w-[280px] mx-auto">
                {errorMessage ||
                  "An unknown error occurred while processing your transaction."}
              </DialogDescription>
            </div>

            <div className="w-full space-y-2 mt-4">
              <Button
                onClick={() => handleOpenChange(false)}
                className="w-full"
                variant="outline"
              >
                Dismiss
              </Button>
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

'use client';

import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import { normalizeDecimalString } from '@/lib/amount-input';
import { useState, useCallback, useEffect, useId } from 'react';

interface AmountInputProps {
  value: string;
  onChange?: (value: string) => void;
  onMax?: () => void;
  placeholder?: string;
  disabled?: boolean;
  readOnly?: boolean;
  className?: string;
  label?: string;
  balance?: string;
  showMax?: boolean;
}

export function AmountInput({
  value,
  onChange,
  onMax,
  placeholder = '0.00',
  disabled = false,
  readOnly = false,
  className,
  label,
  balance,
  showMax = true,
}: AmountInputProps) {
  const [internalValue, setInternalValue] = useState(value);
  const inputId = useId();

  useEffect(() => {
    setInternalValue(value);
  }, [value]);

  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const raw = e.target.value;
      
      // Allow empty string, single dot, or numbers
      if (raw === '' || raw === '.') {
        setInternalValue(raw);
        onChange?.(raw);
        return;
      }

      // Basic numeric validation before heavy normalization
      if (!/^\d*\.?\d*$/.test(raw)) {
        return;
      }

      setInternalValue(raw);
      onChange?.(raw);
    },
    [onChange]
  );

  return (
    <div className={cn("flex flex-col gap-1.5 w-full", className)}>
      <div className="flex justify-between items-center px-1">
        {label && (
          <label htmlFor={inputId} className="text-xs font-medium text-muted-foreground uppercase tracking-wider">
            {label}
          </label>
        )}
        {balance && (
          <span className="text-xs text-muted-foreground">
            Balance: <span className="font-medium text-foreground/80">{balance}</span>
          </span>
        )}
      </div>
      
      <div className="relative group">
        <Input
          id={inputId}
          type="text"
          inputMode="decimal"
          placeholder={placeholder}
          value={internalValue}
          onChange={handleChange}
          disabled={disabled}
          readOnly={readOnly}
          className={cn(
            "h-14 text-2xl font-semibold bg-background/40 border-border/40 focus-visible:ring-primary/30 rounded-xl px-4",
            readOnly && "cursor-default border-transparent bg-transparent px-0 text-3xl",
            !readOnly && "group-hover:border-primary/20 transition-all shadow-sm"
          )}
        />
        
        {showMax && onMax && !readOnly && !disabled && (
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={onMax}
            className="absolute right-2 top-1/2 -translate-y-1/2 h-8 px-3 text-xs font-bold text-primary hover:bg-primary/10 hover:text-primary rounded-lg transition-colors"
          >
            MAX
          </Button>
        )}
      </div>
    </div>
  );
}

'use client';

import { Info, HelpCircle } from "lucide-react";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";
import { Skeleton } from "@/components/ui/skeleton";

interface PriceInfoPanelProps {
  rate?: string;
  priceImpact?: number;
  minReceived?: string;
  networkFee?: string;
  isLoading?: boolean;
}

export function PriceInfoPanel({
  rate,
  priceImpact = 0,
  minReceived,
  networkFee,
  isLoading = false,
}: PriceInfoPanelProps) {
  if (isLoading) {
    return (
      <div className="rounded-2xl border border-border/40 bg-background/40 backdrop-blur-sm p-4 space-y-3">
        <Skeleton className="h-4 w-full opacity-50" />
        <Skeleton className="h-4 w-3/4 opacity-50" />
        <Skeleton className="h-4 w-1/2 opacity-50" />
      </div>
    );
  }

  const getImpactColor = (impact: number) => {
    if (impact < 1) return "text-emerald-500";
    if (impact < 5) return "text-amber-500";
    return "text-destructive";
  };

  const impactColor = getImpactColor(priceImpact);

  return (
    <div className="rounded-2xl border border-border/40 bg-background/40 backdrop-blur-sm p-4 space-y-3 transition-all duration-300 hover:border-primary/20">
      <div className="flex justify-between items-center text-sm">
        <div className="flex items-center gap-1.5 text-muted-foreground font-medium">
          <span>Exchange Rate</span>
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <HelpCircle className="h-3.5 w-3.5 opacity-50 cursor-help" />
              </TooltipTrigger>
              <TooltipContent>
                <p className="text-xs">Current market rate for this trading pair inclusive of path routing.</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
        <span className="font-bold text-foreground/90 tabular-nums">
          {rate || '—'}
        </span>
      </div>

      <div className="flex justify-between items-center text-sm">
        <div className="flex items-center gap-1.5 text-muted-foreground font-medium">
          <span>Price Impact</span>
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <HelpCircle className="h-3.5 w-3.5 opacity-50 cursor-help" />
              </TooltipTrigger>
              <TooltipContent>
                <p className="text-xs">The difference between the market price and your estimated price due to trade size.</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
        <span className={cn("font-bold tabular-nums", impactColor)}>
          {priceImpact > 0 ? `${priceImpact.toFixed(2)}%` : '< 0.01%'}
        </span>
      </div>

      <div className="flex justify-between items-center text-sm">
        <div className="flex items-center gap-1.5 text-muted-foreground font-medium">
          <span>Minimum Received</span>
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <HelpCircle className="h-3.5 w-3.5 opacity-50 cursor-help" />
              </TooltipTrigger>
              <TooltipContent>
                <p className="text-xs">Your transaction will revert if there is a large unfavorable price movement before it is confirmed.</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
        <span className="font-bold text-foreground/90 tabular-nums">
          {minReceived || '—'}
        </span>
      </div>

      <div className="pt-2 mt-1 border-t border-border/20 flex justify-between items-center text-sm">
        <div className="flex items-center gap-1.5 text-muted-foreground font-medium">
          <span>Network Fee</span>
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <HelpCircle className="h-3.5 w-3.5 opacity-50 cursor-help" />
              </TooltipTrigger>
              <TooltipContent>
                <p className="text-xs">Estimated cost to execute this transaction on the Stellar network.</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
        <span className="font-medium text-foreground/70 tabular-nums">
          {networkFee || '—'}
        </span>
      </div>
    </div>
  );
}

import { Skeleton } from "@/components/ui/skeleton";

import { QuoteSummarySkeleton } from "./QuoteSummarySkeleton";

interface QuoteSummaryProps {
  rate: string;
  fee: string;
  priceImpact: string;
  isLoading?: boolean;
}

export function QuoteSummary({
  rate,
  fee,
  priceImpact,
  isLoading = false,
}: QuoteSummaryProps) {
  if (isLoading) {
    return <QuoteSummarySkeleton />;
  }

  const displayRate = rate?.trim() || null;
  const displayFee = fee?.trim() || null;
  const displayPriceImpact = priceImpact?.trim() || null;

  return (
    <div className="rounded-xl border border-border/50 p-4 space-y-3 bg-muted/30">
      {rate && (
        <div className="flex justify-between items-center text-sm">
          <span className="text-muted-foreground">Rate</span>
          <span className="font-medium truncate max-w-[60%]">{rate}</span>
        </div>
      )}
      {fee && (
        <div className="flex justify-between items-center text-sm">
          <span className="text-muted-foreground">Network Fee</span>
          <span className="font-medium truncate max-w-[60%]">{fee}</span>
        </div>
      )}
      {priceImpact && (
        <div className="flex justify-between items-center text-sm">
          <span className="text-muted-foreground">Price Impact</span>
          <span className="font-medium text-emerald-500 min-w-0 truncate max-w-[60%]">
            {priceImpact}
          </span>
        </div>
      )}
    </div>
  );
}

'use client';

import { Skeleton } from "@/components/ui/skeleton";
import { ArrowRight, Info, ChevronDown, MapPin } from "lucide-react";
import { useState, useMemo, useRef } from "react";
import { useVirtualizer } from "@tanstack/react-virtual";
import { Badge } from "@/components/ui/badge";
import { ConfidenceIndicator } from "./ConfidenceIndicator";
import { RouteDisplaySkeleton } from "./RouteDisplaySkeleton";
import { cn } from "@/lib/utils";

interface RouteDisplayProps {
  route: string[];
  amountOut: string;
  confidenceScore?: number;
  volatility?: "high" | "medium" | "low";
  isLoading?: boolean;
}

// VIRTUALIZATION_THRESHOLD: The number of items beyond which the route details list is virtualized.
const VIRTUALIZATION_THRESHOLD = 10;

export function RouteDisplay({
  route,
  amountOut,
  confidenceScore = 85,
  volatility = "low",
  isLoading = false,
}: RouteDisplayProps) {
  const [showDetails, setShowDetails] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const hops = useMemo(() => route.slice(0, -1), [route]);
  const isVirtualized = hops.length >= VIRTUALIZATION_THRESHOLD;

  const rowVirtualizer = useVirtualizer({
    count: hops.length,
    getScrollElement: () => scrollRef.current,
    estimateSize: () => 40, // height of a hop item + margin/padding approx
    overscan: 3,
  });

  if (isLoading) {
    return <RouteDisplaySkeleton />;
  }

  if (!route || route.length < 2) {
    return null;
  }

  return (
    <div className="rounded-2xl border border-border/40 bg-background/40 backdrop-blur-sm p-4 space-y-4 transition-all duration-300 hover:border-primary/20 hover:shadow-md group">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="p-1.5 rounded-lg bg-primary/10 text-primary">
            <MapPin className="h-3.5 w-3.5" />
          </div>
          <h4 className="text-sm font-semibold tracking-tight text-foreground/90">Optimal Route</h4>
        </div>
        <div className="flex items-center gap-2">
          <ConfidenceIndicator score={confidenceScore} volatility={volatility} />
          <Badge variant="secondary" className="text-[10px] font-bold uppercase tracking-wider bg-emerald-500/10 text-emerald-600 hover:bg-emerald-500/20 border-emerald-500/20 px-1.5 h-5 transition-colors">
            Best Price
          </Badge>
          <button
            type="button"
            onClick={() => setShowDetails((prev) => !prev)}
            aria-expanded={showDetails}
            className="h-8 w-8 flex items-center justify-center rounded-full hover:bg-muted/80 transition-all active:scale-90"
          >
            <ChevronDown
              className={cn(
                "h-4 w-4 text-muted-foreground transition-transform duration-300",
                showDetails ? "rotate-180" : ""
              )}
            />
          </button>
        </div>
      </div>

      <div className="relative flex items-center justify-between px-2 py-3 bg-muted/30 rounded-xl border border-border/20">
        {route.map((token, index) => (
          <div key={`route-${index}-${token}`} className="flex items-center gap-2 flex-1 justify-center first:justify-start last:justify-end">
            <div className="flex flex-col items-center sm:items-start">
              <span className="text-xs font-bold text-foreground">{token}</span>
              {index === route.length - 1 && (
                <span className="text-[10px] text-muted-foreground font-medium truncate max-w-[70px]">
                  {parseFloat(amountOut).toFixed(4)}
                </span>
              )}
            </div>
            {index < route.length - 1 && (
              <div className="flex items-center justify-center flex-1 min-w-[30px] px-1">
                <div className="h-[1px] flex-1 bg-border/60 relative">
                  <ArrowRight className="h-3 w-3 text-muted-foreground absolute left-1/2 -translate-x-1/2 -translate-y-1/2 bg-transparent" />
                </div>
              </div>
            )}
          </div>
        ))}
      </div>

      {showDetails && (
        <div className="pt-3 border-t border-border/20 animate-in fade-in slide-in-from-top-1 duration-200">
          <div className="space-y-2">
            <div className="flex items-center justify-between text-[11px] text-muted-foreground font-medium uppercase tracking-wider">
              <span>Hops</span>
              <span>Provider</span>
            </div>
            {route.length > 2 ? (
              isVirtualized ? (
                <div
                  ref={scrollRef}
                  className="max-h-[250px] overflow-auto pr-2"
                >
                  <div
                    style={{
                      height: `${rowVirtualizer.getTotalSize()}px`,
                      width: '100%',
                      position: 'relative',
                    }}
                  >
                    {rowVirtualizer.getVirtualItems().map((virtualRow) => {
                      const i = virtualRow.index;
                      const token = hops[i];
                      return (
                        <div
                          key={`hop-${i}`}
                          ref={rowVirtualizer.measureElement}
                          data-index={virtualRow.index}
                          className="flex items-center justify-between p-2 rounded-lg bg-background/50 border border-border/10 text-xs absolute w-full"
                          style={{
                            top: 0,
                            left: 0,
                            transform: `translateY(${virtualRow.start}px)`,
                          }}
                        >
                          <div className="flex items-center gap-2">
                            <span className="font-semibold">{token}</span>
                            <ArrowRight className="h-3 w-3 text-muted-foreground" />
                            <span className="font-semibold">{route[i + 1]}</span>
                          </div>
                          <span className="text-[10px] font-medium px-1.5 py-0.5 rounded-md bg-muted text-muted-foreground">
                            {i % 2 === 0 ? 'AQUA Pool' : 'Orderbook'}
                          </span>
                        </div>
                      );
                    })}
                  </div>
                </div>
              ) : (
                <div className="space-y-1.5">
                  {hops.map((token, i) => (
                    <div key={`hop-${i}`} className="flex items-center justify-between p-2 rounded-lg bg-background/50 border border-border/10 text-xs">
                      <div className="flex items-center gap-2">
                        <span className="font-semibold">{token}</span>
                        <ArrowRight className="h-3 w-3 text-muted-foreground" />
                        <span className="font-semibold">{route[i+1]}</span>
                      </div>
                      <span className="text-[10px] font-medium px-1.5 py-0.5 rounded-md bg-muted text-muted-foreground">
                        {i % 2 === 0 ? 'AQUA Pool' : 'Orderbook'}
                      </span>
                    </div>
                  ))}
                </div>
              )
            ) : (
              <div className="flex items-center justify-between p-2 rounded-lg bg-background/50 border border-border/10 text-xs">
                <div className="flex items-center gap-2">
                  <span className="font-semibold">{route[0]}</span>
                  <ArrowRight className="h-3 w-3 text-muted-foreground" />
                  <span className="font-semibold">{route[1]}</span>
                </div>
                <span className="text-[10px] font-medium px-1.5 py-0.5 rounded-md bg-muted text-muted-foreground">
                  Direct Path
                </span>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

import { act, cleanup, render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { afterEach, beforeEach, describe, expect, it, vi, Mock } from "vitest";
import { SwapCard } from "./SwapCard";

function setNavigatorOnline(value: boolean) {
  Object.defineProperty(window.navigator, "onLine", {
    configurable: true,
    value,
  });
}

describe("SwapCard network resilience and states", () => {
  beforeEach(() => {
    localStorage.clear();
    global.fetch = vi.fn(() => 
      Promise.resolve({
        ok: true,
        json: () => Promise.resolve({
          total: "9.5",
          price_impact: "0.5",
          path: [],
          price: "0.95",
          amount: "10"
        })
      })
    ) as Mock;
  });

  afterEach(() => {
    cleanup();
    vi.useRealTimers();
    vi.restoreAllMocks();
  });

  it("should render successfully", () => {
    render(<SwapCard />);
    expect(screen.getByRole("heading", { name: /swap/i })).toBeInTheDocument();
  });

  it("shows initial state requiring wallet connection", async () => {
    render(<SwapCard />);
    
    // Check for "Connect Wallet" button
    const connectButton = screen.getByRole("button", { name: /connect wallet/i });
    expect(connectButton).toBeInTheDocument();
  });

  it("transitions states after wallet connection", async () => {
    const user = userEvent.setup();
    render(<SwapCard />);
    
    // 1. Connect Wallet
    const connectButton = screen.getByRole("button", { name: /connect wallet/i });
    await user.click(connectButton);
    
    // 2. Should show "Enter Amount"
    await waitFor(() => {
      expect(screen.getByText(/enter amount/i)).toBeInTheDocument();
    });
    
    // 3. Enter amount
    const payInput = screen.getByLabelText(/you pay/i);
    await user.type(payInput, "10");
    
    // 4. Should show "Swap" button
    await waitFor(() => {
      expect(screen.getByRole("button", { name: /^swap$/i })).toBeEnabled();
    }, { timeout: 3000 });
  });

  it("shows high price impact warning for large amounts", async () => {
    // Override fetch mock for this test to return high price impact
    global.fetch = vi.fn(() => 
      Promise.resolve({
        ok: true,
        json: () => Promise.resolve({
          total: "50",
          price_impact: "15.0", // > 10
          path: [],
          price: "0.5",
          amount: "90" // 90 is <= 100 mock balance, so insufficient_balance won't trigger
        })
      })
    ) as Mock;

    const user = userEvent.setup();
    render(<SwapCard />);
    
    // Connect
    await user.click(screen.getByRole("button", { name: /connect wallet/i }));
    
    // Enter amount
    const payInput = screen.getByLabelText(/you pay/i);
    await user.type(payInput, "90");
    
    await waitFor(() => {
      const impactButton = screen.getByRole("button", { name: /price impact too high/i });
      expect(impactButton).toBeDisabled();
    }, { timeout: 3000 });
  });

  it("shows insufficient balance state", async () => {
    const user = userEvent.setup();
    render(<SwapCard />);
    
    // Connect
    await user.click(screen.getByRole("button", { name: /connect wallet/i }));
    
    // Enter amount higher than mock balance (100.00)
    const payInput = screen.getByLabelText(/you pay/i);
    await user.type(payInput, "100.01");
    
    await waitFor(() => {
      const balanceButton = screen.getByRole("button", { name: /insufficient balance/i });
      expect(balanceButton).toBeDisabled();
    }, { timeout: 3000 });
  });
});

'use client';

import { useState, useCallback, useMemo } from 'react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { ArrowUpDown, RefreshCw, Settings2 } from 'lucide-react';
import { AmountInput } from './AmountInput';
import { TokenSelector } from './TokenSelector';
import { PriceInfoPanel } from './PriceInfoPanel';
import { RouteDisplay } from './RouteDisplay';
import { SwapButton, SwapButtonState } from './SwapButton';
import { useSwapState } from '@/hooks/useSwapState';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';

export function SwapCard() {
  const {
    fromToken,
    setFromToken,
    toToken,
    setToToken,
    fromAmount,
    setFromAmount,
    toAmount,
    slippage,
    setSlippage,
    quote,
    switchTokens,
    formattedRate,
  } = useSwapState();

  const [isConnected, setIsConnected] = useState(false);
  const [isSwapping, setIsSwapping] = useState(false);
  
  // Mock balance
  const fromBalance = "100.00"; 
  const fromSymbol = fromToken === 'native' ? 'XLM' : fromToken.split(':')[0];
  const toSymbol = toToken === 'native' ? 'XLM' : toToken.split(':')[0];

  const buttonState = useMemo<SwapButtonState>(() => {
    if (isSwapping) return "executing";
    if (!isConnected) return "no_wallet";
    if (!fromAmount || parseFloat(fromAmount) === 0) return "no_amount";
    if (parseFloat(fromAmount) > parseFloat(fromBalance)) return "insufficient_balance";
    if (quote.priceImpact > 10) return "high_price_impact";
    if (quote.error) return "error";
    return "ready";
  }, [isConnected, fromAmount, fromBalance, quote.priceImpact, quote.error, isSwapping]);

  const handleSwap = useCallback(async () => {
    setIsSwapping(true);
    // Simulate transaction delay
    await new Promise(resolve => setTimeout(resolve, 2000));
    setIsSwapping(false);
    toast.success(`Successfully swapped ${fromAmount} ${fromSymbol} for ${parseFloat(toAmount).toFixed(4)} ${toSymbol}`);
  }, [fromAmount, fromSymbol, toAmount, toSymbol]);

  const handleMax = useCallback(() => {
    setFromAmount(fromBalance);
  }, [fromBalance, setFromAmount]);

  return (
    <div className="w-full max-w-[480px] mx-auto perspective-1000">
      <Card className="relative overflow-hidden border-border/40 bg-background/60 backdrop-blur-xl shadow-2xl rounded-[32px] transition-all duration-500 hover:shadow-primary/5">
        {/* Animated Background Gradients */}
        <div className="absolute -top-24 -left-24 w-48 h-48 bg-primary/10 rounded-full blur-3xl animate-pulse" />
        <div className="absolute -bottom-24 -right-24 w-48 h-48 bg-blue-500/10 rounded-full blur-3xl animate-pulse delay-700" />
        
        <CardContent className="p-6 space-y-4">
          {/* Header */}
          <div className="flex items-center justify-between mb-2">
            <h2 className="text-xl font-bold tracking-tight bg-gradient-to-br from-foreground to-foreground/60 bg-clip-text text-transparent">
              Swap
            </h2>
            <div className="flex items-center gap-1">
              <Button variant="ghost" size="icon" className="h-9 w-9 rounded-xl hover:bg-muted/80">
                <Settings2 className="h-4.5 w-4.5 text-muted-foreground" />
              </Button>
              <Button 
                variant="ghost" 
                size="icon" 
                onClick={() => quote.refresh()} 
                disabled={quote.loading}
                className="h-9 w-9 rounded-xl hover:bg-muted/80"
              >
                <RefreshCw className={cn("h-4.5 w-4.5 text-muted-foreground", quote.loading && "animate-spin")} />
              </Button>
            </div>
          </div>

          {/* Pay Section */}
          <div className="space-y-2 group">
            <div className="bg-muted/30 hover:bg-muted/40 transition-colors rounded-2xl p-4 border border-border/20 focus-within:border-primary/30 focus-within:ring-4 focus-within:ring-primary/5">
              <div className="flex justify-between items-start mb-1">
                <AmountInput
                  label="You Pay"
                  value={fromAmount}
                  onChange={setFromAmount}
                  onMax={handleMax}
                  balance={`${fromBalance} ${fromSymbol}`}
                  className="flex-1"
                />
                <TokenSelector
                  selectedAsset={fromToken}
                  onSelect={setFromToken}
                  className="mt-6"
                />
              </div>
            </div>
          </div>

          {/* Toggle Button */}
          <div className="relative h-2 flex items-center justify-center z-10">
            <Button
              variant="outline"
              size="icon"
              onClick={switchTokens}
              className="absolute h-10 w-10 rounded-xl bg-background border-border/40 shadow-lg hover:shadow-primary/20 hover:border-primary/40 hover:scale-110 active:scale-95 transition-all duration-300 group"
            >
              <ArrowUpDown className="h-4 w-4 text-primary group-hover:rotate-180 transition-transform duration-500" />
            </Button>
          </div>

          {/* Receive Section */}
          <div className="space-y-2">
            <div className="bg-muted/30 rounded-2xl p-4 border border-border/20">
              <div className="flex justify-between items-start mb-1">
                <AmountInput
                  label="You Receive"
                  value={toAmount}
                  readOnly
                  placeholder="0.00"
                  className="flex-1"
                  showMax={false}
                />
                <TokenSelector
                  selectedAsset={toToken}
                  onSelect={setToToken}
                  className="mt-6"
                />
              </div>
            </div>
          </div>

          {/* Info Panels (Conditional) */}
          {parseFloat(fromAmount) > 0 && (
            <div className="space-y-3 pt-2 animate-in fade-in slide-in-from-bottom-2 duration-500">
              <PriceInfoPanel
                rate={formattedRate}
                priceImpact={quote.priceImpact}
                minReceived={`${(parseFloat(toAmount || '0') * (1 - slippage / 100)).toFixed(4)} ${toSymbol}`}
                networkFee={quote.fee ? `${quote.fee.toFixed(5)} XLM` : '0.00001 XLM'}
                isLoading={quote.loading}
              />
              <RouteDisplay
                route={quote.route}
                amountOut={toAmount}
                isLoading={quote.loading}
              />
            </div>
          )}

          {/* Action Button */}
          <div className="pt-2">
            <SwapButton
              state={buttonState}
              onSwap={handleSwap}
              onConnectWallet={() => setIsConnected(true)}
              isLoading={quote.loading}
            />
          </div>
          
          {/* Status/Error Messages */}
          {quote.error && (
            <p className="text-center text-xs font-medium text-destructive animate-pulse">
              {quote.error.message}
            </p>
          )}
        </CardContent>
      </Card>
      
      {/* Footer Info */}
      <p className="text-center text-[10px] text-muted-foreground/60 mt-4 px-8 uppercase tracking-widest font-bold">
        Powered by StellarRoute Aggregator
      </p>
    </div>
  );
}

"use client";

import React, { useMemo, useState } from "react";
import { ArrowLeftRight } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Skeleton } from "@/components/ui/skeleton";
import { cn } from "@/lib/utils";
import { toast } from "sonner";
import type { TradingPair } from "@/types";
import { TokenSearchModal } from "@/components/shared/TokenSearchModal";
import { useRecentTokens } from "@/hooks/useRecentTokens";

export interface TokenPairSelectorProps {
  /** Available trading pairs from the API */
  pairs: TradingPair[];
  /** Currently selected base asset (sell) */
  selectedBase?: string;
  /** Currently selected quote asset (buy) */
  selectedQuote?: string;
  /** Callback when pair selection changes */
  onPairChange: (base: string, quote: string) => void;
  /** Loading state */
  loading?: boolean;
  /** Error message when no valid pair exists */
  error?: string;
  /** Optional className for styling */
  className?: string;
}

interface AssetOption {
  code: string;
  asset: string;
  issuer?: string;
  displayName: string;
}

function truncateIssuer(issuer: string, maxLength = 12): string {
  if (issuer.length <= maxLength) return issuer;
  return `${issuer.slice(0, 6)}...${issuer.slice(-4)}`;
}

function parseAsset(assetString: string): { code: string; issuer?: string } {
  if (assetString === "native") {
    return { code: "XLM" };
  }
  const parts = assetString.split(":");
  return {
    code: parts[0],
    issuer: parts[1],
  };
}

function AssetButton({
  label,
  code,
  issuer,
  onClick,
  disabled,
}: {
  label: string;
  code: string;
  issuer?: string;
  onClick: () => void;
  disabled?: boolean;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      disabled={disabled}
      className={cn(
        "flex flex-col items-start gap-1 rounded-lg border bg-background p-3 transition-colors hover:bg-accent disabled:opacity-50 disabled:cursor-not-allowed",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
      )}
    >
      <span className="text-xs text-muted-foreground">{label}</span>
      <span className="text-lg font-semibold">{code || "Select"}</span>
      {issuer && (
        <span className="text-xs text-muted-foreground font-mono">
          {truncateIssuer(issuer)}
        </span>
      )}
    </button>
  );
}

export function TokenPairSelector({
  pairs,
  selectedBase,
  selectedQuote,
  onPairChange,
  loading = false,
  error,
  className,
}: TokenPairSelectorProps) {
  const [baseDialogOpen, setBaseDialogOpen] = useState(false);
  const [quoteDialogOpen, setQuoteDialogOpen] = useState(false);
  const { addRecentToken } = useRecentTokens();

  const { baseAssets, quoteAssets, validPairs } = useMemo(() => {
    const baseSet = new Map<string, AssetOption>();
    const quoteSet = new Map<string, AssetOption>();
    const pairMap = new Map<string, Set<string>>();

    pairs.forEach((pair) => {
      const baseInfo = parseAsset(pair.base_asset);
      const quoteInfo = parseAsset(pair.counter_asset);

      baseSet.set(pair.base_asset, {
        code: pair.base,
        asset: pair.base_asset,
        issuer: baseInfo.issuer,
        displayName: pair.base,
      });

      quoteSet.set(pair.counter_asset, {
        code: pair.counter,
        asset: pair.counter_asset,
        issuer: quoteInfo.issuer,
        displayName: pair.counter,
      });

      if (!pairMap.has(pair.base_asset)) {
        pairMap.set(pair.base_asset, new Set());
      }
      pairMap.get(pair.base_asset)!.add(pair.counter_asset);
    });

    return {
      baseAssets: Array.from(baseSet.values()).sort((a, b) =>
        a.code.localeCompare(b.code)
      ),
      quoteAssets: Array.from(quoteSet.values()).sort((a, b) =>
        a.code.localeCompare(b.code)
      ),
      validPairs: pairMap,
    };
  }, [pairs]);

  const availableQuoteAssets = useMemo(() => {
    if (!selectedBase) return quoteAssets;
    const validQuotes = validPairs.get(selectedBase);
    if (!validQuotes) return [];
    return quoteAssets.filter((asset) => validQuotes.has(asset.asset));
  }, [selectedBase, quoteAssets, validPairs]);

  const selectedBaseInfo = useMemo(() => {
    if (!selectedBase) return null;
    return baseAssets.find((a) => a.asset === selectedBase);
  }, [selectedBase, baseAssets]);

  const selectedQuoteInfo = useMemo(() => {
    if (!selectedQuote) return null;
    return quoteAssets.find((a) => a.asset === selectedQuote);
  }, [selectedQuote, quoteAssets]);

  const isPairValid = useMemo(() => {
    if (!selectedBase || !selectedQuote) return true;
    return validPairs.get(selectedBase)?.has(selectedQuote) ?? false;
  }, [selectedBase, selectedQuote, validPairs]);

  const canSwapSides = useMemo(() => {
    if (!selectedBase || !selectedQuote) return false;
    return validPairs.get(selectedQuote)?.has(selectedBase) ?? false;
  }, [selectedBase, selectedQuote, validPairs]);

  const handleSwapSides = () => {
    if (!selectedBase || !selectedQuote) return;
    if (canSwapSides) {
      onPairChange(selectedQuote, selectedBase);
    } else {
      toast.error("This pair cannot be swapped", {
        description: "The reverse trading pair is not available",
      });
    }
  };

  const handleBaseSelect = (asset: string) => {
    if (selectedQuote && !validPairs.get(asset)?.has(selectedQuote)) {
      onPairChange(asset, "");
    } else {
      onPairChange(asset, selectedQuote || "");
    }
    addRecentToken(asset);
  };

  const handleQuoteSelect = (asset: string) => {
    onPairChange(selectedBase || "", asset);
    addRecentToken(asset);
  };

  return (
    <Card className={cn("p-4", className)}>
      <div className="space-y-4">
        <div className="flex items-center gap-3">
          <div className="flex-1">
            {loading ? (
              <Skeleton className="h-[74px] w-full rounded-lg" />
            ) : (
              <AssetButton
                label="You sell"
                code={selectedBaseInfo?.code || ""}
                issuer={selectedBaseInfo?.issuer}
                onClick={() => setBaseDialogOpen(true)}
                disabled={loading || pairs.length === 0}
              />
            )}
          </div>

          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={handleSwapSides}
            disabled={
              loading || !selectedBase || !selectedQuote || !canSwapSides
            }
            title="Swap base and quote assets"
            className="shrink-0"
          >
            <ArrowLeftRight className="h-4 w-4" />
            <span className="sr-only">Swap base and quote assets</span>
          </Button>

          <div className="flex-1">
            {loading ? (
              <Skeleton className="h-[74px] w-full rounded-lg" />
            ) : (
              <AssetButton
                label="You buy"
                code={selectedQuoteInfo?.code || ""}
                issuer={selectedQuoteInfo?.issuer}
                onClick={() => setQuoteDialogOpen(true)}
                disabled={loading || pairs.length === 0 || !selectedBase}
              />
            )}
          </div>
        </div>

        {!isPairValid && selectedBase && selectedQuote && (
          <div className="rounded-md bg-destructive/10 border border-destructive/20 p-3">
            <p className="text-sm text-destructive font-medium">
              Invalid pair selection
            </p>
            <p className="text-xs text-destructive/80 mt-1">
              This trading pair is not available. Please{" "}
              <button
