import { useState, useCallback, useMemo } from 'react';
import { useTradeFormStorage } from './useTradeFormStorage';
import { useQuote } from './useQuote';

const DEFAULT_FROM_TOKEN = 'native';
const DEFAULT_TO_TOKEN = 'USDC:GA5ZSEJYB37JRC5AVCIAZDL2Y343IFRMA2EO3HJWV2XG7H5V5CQRUP7W';

export function useSwapState() {
  const { amount: fromAmount, setAmount: setFromAmount, slippage, setSlippage, reset } = useTradeFormStorage();
  
  const [fromToken, setFromToken] = useState(DEFAULT_FROM_TOKEN);
  const [toToken, setToToken] = useState(DEFAULT_TO_TOKEN);
  
  const parsedAmount = useMemo(() => {
    const val = parseFloat(fromAmount);
    return isFinite(val) && val > 0 ? val : undefined;
  }, [fromAmount]);

  const quote = useQuote({
    fromToken,
    toToken,
    amount: parsedAmount,
    type: 'sell',
  });

  const switchTokens = useCallback(() => {
    setFromToken(toToken);
    setToToken(fromToken);
    // If we have an output amount, we might want to set it as the new input amount
    if (quote.outputAmount > 0) {
      setFromAmount(quote.outputAmount.toString());
    }
  }, [fromToken, toToken, quote.outputAmount, setFromAmount]);

  const isReverseRate = false; // Could be state to toggle rate display (e.g. 1 XLM = 0.1 USDC vs 1 USDC = 10 XLM)
  
  const formattedRate = useMemo(() => {
    if (!quote.rate) return '';
    const fromSymbol = fromToken === 'native' ? 'XLM' : fromToken.split(':')[0];
    const toSymbol = toToken === 'native' ? 'XLM' : toToken.split(':')[0];
    return `1 ${fromSymbol} = ${quote.rate.toFixed(4)} ${toSymbol}`;
  }, [quote.rate, fromToken, toToken]);

  return {
    fromToken,
    setFromToken,
    toToken,
    setToToken,
    fromAmount,
    setFromAmount,
    toAmount: quote.outputAmount > 0 ? quote.outputAmount.toString() : '',
    slippage,
    setSlippage,
    quote,
    switchTokens,
    formattedRate,
    reset,
  };
}

"use client";

import { useCallback, useEffect, useState } from "react";
import { useRouter, useSearchParams, usePathname } from "next/navigation";

export interface UseTokenPairUrlResult {
  /** Currently selected base asset from URL */
  base: string | undefined;
  /** Currently selected quote asset from URL */
  quote: string | undefined;
  /** Update both base and quote in URL */
  setPair: (base: string, quote: string) => void;
  /** Whether the URL state is being initialized */
  isInitializing: boolean;
}

/**
 * Hook to manage token pair selection in URL query parameters.
 * 
 * Syncs base and quote assets with URL params (?base=native&quote=USDC:ISSUER)
 * so that refresh and back/forward navigation work correctly.
 * 
 * @example
 * ```tsx
 * const { base, quote, setPair } = useTokenPairUrl();
 * 
 * <TokenPairSelector
 *   selectedBase={base}
 *   selectedQuote={quote}
 *   onPairChange={setPair}
 * />
 * ```
 */
export function useTokenPairUrl(): UseTokenPairUrlResult {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const [isInitializing, setIsInitializing] = useState(true);

  const base = searchParams.get("base") || undefined;
  const quote = searchParams.get("quote") || undefined;

  // Mark initialization as complete after first render
   
  useEffect(() => {
    setIsInitializing(false);
  }, []);

  const setPair = useCallback(
    (newBase: string, newQuote: string) => {
      const params = new URLSearchParams(searchParams.toString());

      if (newBase) {
        params.set("base", newBase);
      } else {
        params.delete("base");
      }

      if (newQuote) {
        params.set("quote", newQuote);
      } else {
        params.delete("quote");
      }

      const queryString = params.toString();
      const url = queryString ? `${pathname}?${queryString}` : pathname;

      router.push(url, { scroll: false });
    },
    [pathname, router, searchParams]
  );

  return {
    base,
    quote,
    setPair,
    isInitializing,
  };
}

